"""
AstroHub v2.0 - 设备配置管理

统一管理设备配置：
- 读取/写入 device_config.json
- 当前设备、历史设备
- IP/MAC/型号等信息

Author: 雅痞张@南方天文
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

CONFIG_FILE = Path(__file__).parent.parent.parent / "data" / "device_config.json"


def ensure_config() -> Path:
    """确保配置文件存在。"""
    CONFIG_FILE.parent.mkdir(parents=True, exist_ok=True)
    if not CONFIG_FILE.exists():
        save_config({
            "current_device": None,
            "devices": {}
        })
    return CONFIG_FILE


def load_config() -> dict[str, Any]:
    """加载设备配置。"""
    ensure_config()
    with open(CONFIG_FILE, "r", encoding="utf-8") as f:
        return json.load(f)


def save_config(config: dict[str, Any]) -> None:
    """保存设备配置。"""
    CONFIG_FILE.parent.mkdir(parents=True, exist_ok=True)
    with open(CONFIG_FILE, "w", encoding="utf-8") as f:
        json.dump(config, f, indent=2, ensure_ascii=False)


def get_current_device() -> dict[str, Any] | None:
    """获取当前设备信息。"""
    config = load_config()
    current_mac = config.get("current_device")
    if not current_mac:
        return None
    return config.get("devices", {}).get(current_mac)


def set_current_device(mac: str, ip: str = "", model: str = "", port: int = 80, username: str = "", password: str = "") -> None:
    """设置当前设备。"""
    config = load_config()
    mac_clean = mac.replace(":", "").lower()

    config["current_device"] = mac_clean
    if mac_clean not in config.get("devices", {}):
        config.setdefault("devices", {})[mac_clean] = {}

    config["devices"][mac_clean]["mac"] = mac_clean
    if ip:
        config["devices"][mac_clean]["ip"] = ip
    if model:
        config["devices"][mac_clean]["model"] = model
    config["devices"][mac_clean]["port"] = port
    if username:
        config["devices"][mac_clean]["username"] = username
    if password:
        config["devices"][mac_clean]["password"] = password

    save_config(config)


def update_device_info(mac: str, **kwargs) -> None:
    """更新设备信息。"""
    config = load_config()
    mac_clean = mac.replace(":", "").lower()

    if mac_clean not in config.get("devices", {}):
        config.setdefault("devices", {})[mac_clean] = {"mac": mac_clean}

    config["devices"][mac_clean].update(kwargs)
    save_config(config)


def list_devices() -> list[dict[str, Any]]:
    """列出所有历史设备。"""
    config = load_config()
    return list(config.get("devices", {}).values())


